# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <limits>
#include <chrono>
#include <random>
#include <cmath>
#include <utility>
#include <numeric>
#include <cstring>

// N=200, M=10, each stack has 20 boxes initially
// Plan: For each target k, allow up to 1 split of the block above it.
// Plan entry: (split_pos, dest_lower, dest_upper)
// split_pos=0: no split, move all boxes above target to dest_lower
// split_pos>0: first move top split_pos boxes to dest_upper, then remaining to dest_lower
// This costs 1 extra energy per split but enables better routing.

auto GLOBAL_START_TIME = std::chrono::steady_clock::now();
const double TIME_LIMIT_SECONDS = 1.90;

struct RNG {
    std::mt19937 rng;
    RNG() : rng(std::chrono::steady_clock::now().time_since_epoch().count()) {}
    int randint(int lo, int hi) {
        if (lo > hi) return lo;
        return std::uniform_int_distribution<int>(lo, hi)(rng);
    }
    double randdbl() {
        return std::uniform_real_distribution<double>(0.0, 1.0)(rng);
    }
} rng;

struct PlanEntry {
    int split_pos;   // 0 = no split, >0 = number of top boxes to split off
    int dest_lower;  // destination for lower portion (or all if no split)
    int dest_upper;  // destination for upper portion (only used if split_pos > 0)
};

struct State {
    std::vector<std::vector<int>> stacks; // stacks[i] = boxes from bottom to top, 0-indexed values
    int box_stack[200];  // which stack each box is on
    int box_height[200]; // height index of each box in its stack
    int N, M;
    long long energy;

    void init(int n, int m, const std::vector<std::vector<int>>& initial) {
        N = n; M = m; energy = 0;
        stacks.resize(m);
        for (int i = 0; i < m; i++) {
            stacks[i] = initial[i];
            for (int j = 0; j < (int)stacks[i].size(); j++) {
                box_stack[stacks[i][j]] = i;
                box_height[stacks[i][j]] = j;
            }
        }
    }

    void move_block(int first_box, int num_boxes, int dest) {
        int src = box_stack[first_box];
        int h = box_height[first_box];
        auto& sv = stacks[src];
        auto& dv = stacks[dest];
        int dh = dv.size();
        for (int i = 0; i < num_boxes; i++) {
            int b = sv[h + i];
            dv.push_back(b);
            box_stack[b] = dest;
            box_height[b] = dh + i;
        }
        sv.resize(h);
        energy += (num_boxes + 1);
    }

    void carry_out(int box_val) {
        int src = box_stack[box_val];
        stacks[src].pop_back();
    }
};

struct SimResult {
    long long energy;
    std::vector<std::pair<int,int>> ops; // (box+1, dest+1) or (box+1, 0)
};

SimResult simulate(const std::vector<std::vector<int>>& initial, const std::vector<PlanEntry>& plan,
                   int N, int M, bool record_ops) {
    State st;
    st.init(N, M, initial);
    std::vector<std::pair<int,int>> ops;
    if (record_ops) ops.reserve(N * 3);

    for (int k = 0; k < N; k++) {
        int src = st.box_stack[k];
        int h = st.box_height[k];
        int num_above = (int)st.stacks[src].size() - 1 - h;

        if (num_above > 0) {
            int split_pos = plan[k].split_pos;
            int dest_lower = plan[k].dest_lower;
            int dest_upper = plan[k].dest_upper;

            // Fix invalid destinations
            if (dest_lower == src) dest_lower = (src + 1) % M;
            if (dest_upper == src) dest_upper = (src + 1) % M;

            if (split_pos > 0 && split_pos < num_above) {
                // Split: move top split_pos boxes to dest_upper first
                int top_start_box = st.stacks[src][h + 1 + (num_above - split_pos)];
                st.move_block(top_start_box, split_pos, dest_upper);
                if (record_ops) ops.push_back({top_start_box + 1, dest_upper + 1});

                // Then move remaining (num_above - split_pos) boxes to dest_lower
                int lower_start_box = st.stacks[src][h + 1];
                int lower_count = num_above - split_pos;
                st.move_block(lower_start_box, lower_count, dest_lower);
                if (record_ops) ops.push_back({lower_start_box + 1, dest_lower + 1});
            } else {
                // No split: move all to dest_lower
                int first_box = st.stacks[src][h + 1];
                st.move_block(first_box, num_above, dest_lower);
                if (record_ops) ops.push_back({first_box + 1, dest_lower + 1});
            }
        }
        st.carry_out(k);
        if (record_ops) ops.push_back({k + 1, 0});
    }
    return {st.energy, std::move(ops)};
}

long long simulate_energy(const std::vector<std::vector<int>>& initial, const std::vector<PlanEntry>& plan,
                          int N, int M) {
    return simulate(initial, plan, N, M, false).energy;
}

// Evaluate destination quality for placing a block
double eval_dest(const State& st, int target_k, const std::vector<int>& block, int dest, int N) {
    const auto& dv = st.stacks[dest];
    double score = 0;
    int lookahead = 20;

    if (dv.empty()) {
        score -= 500.0; // Empty stack bonus (but not too much)
    } else {
        // Penalize placing on tall stacks
        score += (double)dv.size() * 0.3;

        // Heavy penalty for burying boxes needed soon
        for (int b : dv) {
            if (b > target_k && b < target_k + lookahead) {
                score += 8.0 * block.size(); // burying a soon-needed box
            }
        }
    }

    // Penalty for soon-needed boxes in our block being buried by other block elements
    for (int i = 0; i < (int)block.size(); i++) {
        int b = block[i];
        if (b > target_k && b < target_k + lookahead) {
            int boxes_on_top = (int)block.size() - 1 - i;
            score += 4.0 * boxes_on_top;
        }
    }

    // Bonus for placing near boxes of similar value range
    if (!dv.empty()) {
        int min_in_dest = *std::min_element(dv.begin(), dv.end());
        score -= (double)min_in_dest * 0.02;
    }

    return score;
}

std::vector<PlanEntry> generate_greedy_plan(const std::vector<std::vector<int>>& initial, int N, int M) {
    std::vector<PlanEntry> plan(N);
    State st;
    st.init(N, M, initial);

    for (int k = 0; k < N; k++) {
        int src = st.box_stack[k];
        int h = st.box_height[k];
        int num_above = (int)st.stacks[src].size() - 1 - h;

        if (num_above == 0) {
            plan[k] = {0, src, 0};
            st.carry_out(k);
            continue;
        }

        // Collect block info
        std::vector<int> block(st.stacks[src].begin() + h + 1, st.stacks[src].end());

        // Try no-split first: find best single destination
        double best_single_score = 1e18;
        int best_single_dest = (src + 1) % M;
        for (int d = 0; d < M; d++) {
            if (d == src) continue;
            double sc = eval_dest(st, k, block, d, N);
            if (sc < best_single_score) {
                best_single_score = sc;
                best_single_dest = d;
            }
        }

        // Try splits: find if splitting can help
        int best_split_pos = 0;
        int best_split_dest_lower = best_single_dest;
        int best_split_dest_upper = best_single_dest;
        double best_split_score = best_single_score;

        if (num_above >= 3) {
            int threshold = k + 20; // "soon needed" threshold
            // Find natural split point based on value ranges
            for (int sp = 1; sp < num_above && sp <= num_above - 1; sp++) {
                // Split: top sp boxes go to dest_upper, bottom (num_above-sp) go to dest_lower
                std::vector<int> lower_block(block.begin(), block.begin() + (num_above - sp));
                std::vector<int> upper_block(block.begin() + (num_above - sp), block.end());

                // Check if this split makes sense (separates near/far)
                bool has_urgent_in_upper = false;
                bool has_nonurgent_in_lower = false;
                for (int b : upper_block) if (b < threshold) has_urgent_in_upper = true;
                for (int b : lower_block) if (b >= threshold) has_nonurgent_in_lower = true;

                // Find best destinations for each portion
                for (int d1 = 0; d1 < M; d1++) {
                    if (d1 == src) continue;
                    double sc1 = eval_dest(st, k, lower_block, d1, N);
                    for (int d2 = 0; d2 < M; d2++) {
                        if (d2 == src) continue;
                        // After placing lower on d1, evaluate upper on d2
                        // (simplified: don't model the intermediate state perfectly)
                        double sc2 = eval_dest(st, k, upper_block, d2, N);
                        double total = sc1 + sc2 + 1.0; // +1 for split cost
                        if (total < best_split_score) {
                            best_split_score = total;
                            best_split_pos = sp;
                            best_split_dest_lower = d1;
                            best_split_dest_upper = d2;
                        }
                    }
                }
            }
        }

        if (best_split_pos > 0) {
            plan[k] = {best_split_pos, best_split_dest_lower, best_split_dest_upper};
            // Apply split
            int top_start = st.stacks[src][h + 1 + (num_above - best_split_pos)];
            st.move_block(top_start, best_split_pos, best_split_dest_upper);
            int lower_start = st.stacks[src][h + 1];
            int lower_count = num_above - best_split_pos;
            st.move_block(lower_start, lower_count, best_split_dest_lower);
        } else {
            plan[k] = {0, best_single_dest, 0};
            int first_box = st.stacks[src][h + 1];
            st.move_block(first_box, num_above, best_single_dest);
        }
        st.carry_out(k);
    }
    return plan;
}

// Fast greedy without splits (for comparison and SA baseline)
std::vector<PlanEntry> generate_simple_greedy(const std::vector<std::vector<int>>& initial, int N, int M) {
    std::vector<PlanEntry> plan(N);
    State st;
    st.init(N, M, initial);

    for (int k = 0; k < N; k++) {
        int src = st.box_stack[k];
        int h = st.box_height[k];
        int num_above = (int)st.stacks[src].size() - 1 - h;

        if (num_above == 0) {
            plan[k] = {0, src, 0};
            st.carry_out(k);
            continue;
        }

        std::vector<int> block(st.stacks[src].begin() + h + 1, st.stacks[src].end());

        double best_score = 1e18;
        int best_dest = (src + 1) % M;
        for (int d = 0; d < M; d++) {
            if (d == src) continue;
            double sc = eval_dest(st, k, block, d, N);
            if (sc < best_score) {
                best_score = sc;
                best_dest = d;
            }
        }

        plan[k] = {0, best_dest, 0};
        int first_box = st.stacks[src][h + 1];
        st.move_block(first_box, num_above, best_dest);
        st.carry_out(k);
    }
    return plan;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;
    std::vector<std::vector<int>> initial_stacks(M, std::vector<int>(N / M));
    for (int i = 0; i < M; i++) {
        for (int j = 0; j < N / M; j++) {
            std::cin >> initial_stacks[i][j];
            initial_stacks[i][j]--; // 0-index
        }
    }

    // Generate initial plan using greedy with splits
    std::vector<PlanEntry> best_plan = generate_greedy_plan(initial_stacks, N, M);
    long long best_energy = simulate_energy(initial_stacks, best_plan, N, M);

    // Also try simple greedy (no splits) as alternative starting point
    std::vector<PlanEntry> simple_plan = generate_simple_greedy(initial_stacks, N, M);
    long long simple_energy = simulate_energy(initial_stacks, simple_plan, N, M);

    if (simple_energy < best_energy) {
        best_plan = simple_plan;
        best_energy = simple_energy;
    }

    // SA optimization
    std::vector<PlanEntry> current_plan = best_plan;
    long long current_energy = best_energy;

    double sa_start_time = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
    double sa_budget = TIME_LIMIT_SECONDS - sa_start_time;
    double T_init = 50.0;
    double T_final = 0.01;

    int sa_iterations = 0;
    while (true) {
        double elapsed = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
        if (elapsed >= TIME_LIMIT_SECONDS) break;

        double progress = (elapsed - sa_start_time) / sa_budget;
        if (progress > 1.0) break;
        double T = T_init * std::pow(T_final / T_init, progress);

        std::vector<PlanEntry> new_plan = current_plan;
        double op = rng.randdbl();

        if (op < 0.3) {
            // Change dest_lower for one entry
            int k = rng.randint(0, N - 1);
            new_plan[k].dest_lower = rng.randint(0, M - 1);
        } else if (op < 0.55) {
            // Change dest_lower for a block of entries
            int start = rng.randint(0, N - 1);
            int len = rng.randint(1, std::max(1, N / 10));
            for (int i = 0; i < len; i++) {
                int idx = (start + i) % N;
                new_plan[idx].dest_lower = rng.randint(0, M - 1);
            }
        } else if (op < 0.70) {
            // Toggle or change split for one entry
            int k = rng.randint(0, N - 1);
            if (new_plan[k].split_pos > 0) {
                // Remove split or change split params
                if (rng.randdbl() < 0.4) {
                    new_plan[k].split_pos = 0;
                } else {
                    new_plan[k].split_pos = rng.randint(1, 15);
                    new_plan[k].dest_upper = rng.randint(0, M - 1);
                }
            } else {
                // Add a split
                new_plan[k].split_pos = rng.randint(1, 10);
                new_plan[k].dest_upper = rng.randint(0, M - 1);
            }
        } else if (op < 0.85) {
            // Change dest_upper for one entry
            int k = rng.randint(0, N - 1);
            if (new_plan[k].split_pos > 0) {
                new_plan[k].dest_upper = rng.randint(0, M - 1);
            } else {
                new_plan[k].dest_lower = rng.randint(0, M - 1);
            }
        } else {
            // Swap destinations between two entries
            int k1 = rng.randint(0, N - 1);
            int k2 = rng.randint(0, N - 1);
            std::swap(new_plan[k1].dest_lower, new_plan[k2].dest_lower);
        }

        long long new_energy = simulate_energy(initial_stacks, new_plan, N, M);

        long long delta = new_energy - current_energy;
        if (delta < 0 || (T > 1e-9 && rng.randdbl() < std::exp(-(double)delta / T))) {
            current_energy = new_energy;
            current_plan = new_plan;
            if (new_energy < best_energy) {
                best_energy = new_energy;
                best_plan = new_plan;
            }
        }
        sa_iterations++;
    }

    // Output best solution
    SimResult result = simulate(initial_stacks, best_plan, N, M, true);
    for (auto& [v, d] : result.ops) {
        std::cout << v << " " << d << "\n";
    }

    return 0;
}
