#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>
#include <chrono>
#include <random>
#include <cmath>
#include <utility>
#include <cstring>

// N=200, M=10, each stack has 20 boxes initially
// Approach: Each target k has a plan entry (split_pos, dest_lower, dest_upper).
// split_pos=0: move all boxes above target to dest_lower
// split_pos>0: split the block - move top split_pos to dest_upper, rest to dest_lower
// Use fast array-based simulation + partial re-simulation from change point.

auto GLOBAL_START_TIME = std::chrono::steady_clock::now();
const double TIME_LIMIT_SECONDS = 1.92;

struct RNG {
    uint64_t s;
    RNG() : s(std::chrono::steady_clock::now().time_since_epoch().count()) {}
    uint64_t next() { s ^= s << 13; s ^= s >> 7; s ^= s << 17; return s; }
    int randint(int lo, int hi) {
        if (lo > hi) return lo;
        return lo + (int)(next() % (uint64_t)(hi - lo + 1));
    }
    double randdbl() { return (next() & 0xFFFFFFFF) / 4294967296.0; }
} rng;

struct PlanEntry {
    int8_t split_pos;
    int8_t dest_lower;
    int8_t dest_upper;
};

// Fast state using fixed arrays
struct FastState {
    int stacks[10][420]; // stacks[i][j] = box at position j, 0-indexed box values
    int stack_sz[10];
    int box_stack[200];
    int box_height[200];
    long long energy;

    void init(int M, const std::vector<std::vector<int>>& initial) {
        energy = 0;
        for (int i = 0; i < M; i++) {
            stack_sz[i] = initial[i].size();
            for (int j = 0; j < stack_sz[i]; j++) {
                stacks[i][j] = initial[i][j];
                box_stack[initial[i][j]] = i;
                box_height[initial[i][j]] = j;
            }
        }
    }

    inline void move_block(int first_box, int num_boxes, int dest, int src, int h) {
        int dh = stack_sz[dest];
        memcpy(&stacks[dest][dh], &stacks[src][h], num_boxes * sizeof(int));
        for (int i = 0; i < num_boxes; i++) {
            int b = stacks[dest][dh + i];
            box_stack[b] = dest;
            box_height[b] = dh + i;
        }
        stack_sz[dest] += num_boxes;
        stack_sz[src] = h;
        energy += (num_boxes + 1);
    }

    inline void carry_out(int box_val) {
        int src = box_stack[box_val];
        stack_sz[src]--;
    }
};

long long simulate_energy(const std::vector<std::vector<int>>& initial, const PlanEntry* plan,
                          int N, int M) {
    FastState st;
    st.init(M, initial);

    for (int k = 0; k < N; k++) {
        int src = st.box_stack[k];
        int h = st.box_height[k];
        int num_above = st.stack_sz[src] - 1 - h;

        if (num_above > 0) {
            int sp = plan[k].split_pos;
            int dl = plan[k].dest_lower;
            int du = plan[k].dest_upper;
            if (dl == src) dl = (src + 1) % M;
            if (du == src) du = (src + 1) % M;

            if (sp > 0 && sp < num_above) {
                // Split: move top sp boxes to du, then remaining to dl
                int top_h = h + 1 + (num_above - sp);
                st.move_block(st.stacks[src][top_h], sp, du, src, top_h);
                // Now remaining (num_above - sp) boxes are at h+1
                int lower_count = num_above - sp;
                st.move_block(st.stacks[src][h + 1], lower_count, dl, src, h + 1);
            } else {
                // No split
                st.move_block(st.stacks[src][h + 1], num_above, dl, src, h + 1);
            }
        }
        st.carry_out(k);
    }
    return st.energy;
}

// Simulate from position k_start, given a state already at that point
long long simulate_from(FastState& st, const PlanEntry* plan, int k_start, int N, int M) {
    for (int k = k_start; k < N; k++) {
        int src = st.box_stack[k];
        int h = st.box_height[k];
        int num_above = st.stack_sz[src] - 1 - h;

        if (num_above > 0) {
            int sp = plan[k].split_pos;
            int dl = plan[k].dest_lower;
            int du = plan[k].dest_upper;
            if (dl == src) dl = (src + 1) % M;
            if (du == src) du = (src + 1) % M;

            if (sp > 0 && sp < num_above) {
                int top_h = h + 1 + (num_above - sp);
                st.move_block(st.stacks[src][top_h], sp, du, src, top_h);
                int lower_count = num_above - sp;
                st.move_block(st.stacks[src][h + 1], lower_count, dl, src, h + 1);
            } else {
                st.move_block(st.stacks[src][h + 1], num_above, dl, src, h + 1);
            }
        }
        st.carry_out(k);
    }
    return st.energy;
}

// Get state at position k_limit (simulate first k_limit steps)
FastState get_state_at(const std::vector<std::vector<int>>& initial, const PlanEntry* plan,
                       int k_limit, int M) {
    FastState st;
    st.init(M, initial);
    for (int k = 0; k < k_limit; k++) {
        int src = st.box_stack[k];
        int h = st.box_height[k];
