void generate_greedy_plan(const std::vector<std::vector<int>>& initial, int N, int M, PlanEntry* plan) {
    FastState st;
    st.init(M, initial);

    for (int k = 0; k < N; k++) {
        int src = st.box_stack[k];
        int h = st.box_height[k];
        int num_above = st.stack_sz[src] - 1 - h;

        if (num_above == 0) {
            plan[k] = {0, (int8_t)src, 0};
            st.carry_out(k);
            continue;
        }

        // Find best single destination
        double best_score = 1e18;
        int best_dest = (src + 1) % M;
        for (int d = 0; d < M; d++) {
            if (d == src) continue;
            double sc = eval_dest(st, k, src, h, num_above, d, N);
            if (sc < best_score) {
                best_score = sc;
                best_dest = d;
            }
        }

        plan[k] = {0, (int8_t)best_dest, 0};
        st.move_block(st.stacks[src][h + 1], num_above, best_dest, src, h + 1);
        st.carry_out(k);
    }
}

