#include <iostream>
#include <vector>
#include <algorithm>
#include <chrono>
#include <cmath>
#include <cstring>

// N=200, M=10, each stack has 20 boxes initially
// Approach: Each target k has a plan entry (split_pos, dest_lower, dest_upper).
// split_pos=0: move all boxes above target to dest_lower
// split_pos>0: split the block - move top split_pos to dest_upper, rest to dest_lower
// Fast array-based simulation + SA with partial re-simulation.

auto GLOBAL_START_TIME = std::chrono::steady_clock::now();
const double TIME_LIMIT_SECONDS = 1.92;

struct RNG {
    uint64_t s;
    RNG() : s(std::chrono::steady_clock::now().time_since_epoch().count() ^ 0x12345678ULL) {}
    inline uint64_t next() { s ^= s << 13; s ^= s >> 7; s ^= s << 17; return s; }
    inline int randint(int lo, int hi) { return lo + (int)(next() % (uint64_t)(hi - lo + 1)); }
    inline double randdbl() { return (next() & 0xFFFFFFFF) / 4294967296.0; }
} rng;

struct PlanEntry {
    int8_t split_pos;
    int8_t dest_lower;
    int8_t dest_upper;
};

struct FastState {
    int stacks[10][420];
    int stack_sz[10];
    int box_stack[200];
    int box_height[200];
    long long energy;

    void init(int M, const std::vector<std::vector<int>>& initial) {
        energy = 0;
        for (int i = 0; i < M; i++) {
            stack_sz[i] = initial[i].size();
            for (int j = 0; j < stack_sz[i]; j++) {
                stacks[i][j] = initial[i][j];
                box_stack[initial[i][j]] = i;
                box_height[initial[i][j]] = j;
            }
        }
    }

    inline void move_block(int num_boxes, int dest, int src, int h) {
        int dh = stack_sz[dest];
        memcpy(&stacks[dest][dh], &stacks[src][h], num_boxes * sizeof(int));
        for (int i = 0; i < num_boxes; i++) {
            int b = stacks[dest][dh + i];
            box_stack[b] = dest;
            box_height[b] = dh + i;
        }
        stack_sz[dest] += num_boxes;
        stack_sz[src] = h;
        energy += (num_boxes + 1);
    }

    inline void carry_out(int box_val) {
        stack_sz[box_stack[box_val]]--;
    }

    inline void apply_step(int k, const PlanEntry& pe, int M) {
        int src = box_stack[k];
        int h = box_height[k];
        int num_above = stack_sz[src] - 1 - h;
        if (num_above > 0) {
            int sp = pe.split_pos;
            int dl = pe.dest_lower;
            int du = pe.dest_upper;
            if (dl == src) dl = (src + 1) % M;
            if (du == src) du = (src + 1) % M;
            if (sp > 0 && sp < num_above) {
                int top_h = h + 1 + (num_above - sp);
                move_block(sp, du, src, top_h);
                move_block(num_above - sp, dl, src, h + 1);
            } else {
                move_block(num_above, dl, src, h + 1);
            }
        }
        carry_out(k);
    }
};

long long simulate_energy_full(const std::vector<std::vector<int>>& initial, const PlanEntry* plan,
                               int N, int M) {
    FastState st;
    st.init(M, initial);
    for (int k = 0; k < N; k++) st.apply_step(k, plan[k], M);
    return st.energy;
}

long long simulate_from(FastState& st, const PlanEntry* plan, int k_start, int N, int M) {
    for (int k = k_start; k < N; k++) st.apply_step(k, plan[k], M);
    return st.energy;
}

FastState get_state_at(const std::vector<std::vector<int>>& initial, const PlanEntry* plan,
                       int k_limit, int M) {
    FastState st;
    st.init(M, initial);
    for (int k = 0; k < k_limit; k++) st.apply_step(k, plan[k], M);
    return st;
}

double eval_dest(const FastState& st, int target_k, int src, int h, int num_above, int dest, int N) {
    double score = 0;
    int dsz = st.stack_sz[dest];
    int lookahead = 15;

    if (dsz == 0) {
        score -= 400.0;
    } else {
        score += (double)dsz * 0.3;
        for (int j = 0; j < dsz; j++) {
            int b = st.stacks[dest][j];
            if (b > target_k && b < target_k + lookahead) {
                score += 6.0 * num_above;
            }
        }
    }

    for (int i = 0; i < num_above; i++) {
        int b = st.stacks[src][h + 1 + i];
        if (b > target_k && b < target_k + lookahead) {
            int boxes_on_top = num_above - 1 - i;
            score += 3.5 * boxes_on_top;
        }
    }

    return score;
}

void generate_greedy_plan(const std::vector<std::vector<int>>& initial, int N, int M, PlanEntry* plan) {
    FastState st;
    st.init(M, initial);

    for (int k = 0; k < N; k++) {
        int src = st.box_stack[k];
        int h = st.box_height[k];
        int num_above = st.stack_sz[src] - 1 - h;

        if (num_above == 0) {
            plan[k] = {0, (int8_t)src, 0};
            st.carry_out(k);
            continue;
        }

        double best_score = 1e18;
        int best_dest = (src + 1) % M;
        for (int d = 0; d < M; d++) {
            if (d == src) continue;
            double sc = eval_dest(st, k, src, h, num_above, d, N);
            if (sc < best_score) {
                best_score = sc;
                best_dest = d;
            }
        }

        plan[k] = {0, (int8_t)best_dest, 0};
        st.move_block(num_above, best_dest, src, h + 1);
        st.carry_out(k);
    }
}

void output_solution(const std::vector<std::vector<int>>& initial, const PlanEntry* plan, int N, int M) {
    FastState st;
    st.init(M, initial);

    for (int k = 0; k < N; k++) {
        int src = st.box_stack[k];
        int h = st.box_height[k];
        int num_above = st.stack_sz[src] - 1 - h;

        if (num_above > 0) {
            int sp = plan[k].split_pos;
            int dl = plan[k].dest_lower;
            int du = plan[k].dest_upper;
            if (dl == src) dl = (src + 1) % M;
            if (du == src) du = (src + 1) % M;

            if (sp > 0 && sp < num_above) {
                int top_h = h + 1 + (num_above - sp);
                int top_box = st.stacks[src][top_h];
                std::cout << (top_box + 1) << " " << (du + 1) << "\n";
                st.move_block(sp, du, src, top_h);

                int lower_box = st.stacks[src][h + 1];
                std::cout << (lower_box + 1) << " " << (dl + 1) << "\n";
                st.move_block(num_above - sp, dl, src, h + 1);
            } else {
                int first_box = st.stacks[src][h + 1];
                std::cout << (first_box + 1) << " " << (dl + 1) << "\n";
                st.move_block(num_above, dl, src, h + 1);
            }
        }
        std::cout << (k + 1) << " " << 0 << "\n";
        st.carry_out(k);
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;
    std::vector<std::vector<int>> initial_stacks(M, std::vector<int>(N / M));
    for (int i = 0; i < M; i++) {
        for (int j = 0; j < N / M; j++) {
            std::cin >> initial_stacks[i][j];
            initial_stacks[i][j]--;
        }
    }

    // Generate initial greedy plan
    PlanEntry best_plan[200];
    generate_greedy_plan(initial_stacks, N, M, best_plan);
    long long best_energy = simulate_energy_full(initial_stacks, best_plan, N, M);

    PlanEntry current_plan[200];
    memcpy(current_plan, best_plan, sizeof(PlanEntry) * N);
    long long current_energy = best_energy;

    // SA optimization with checkpointing
    double sa_start = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
    double sa_budget = TIME_LIMIT_SECONDS - sa_start;
    double T_init = 35.0;
    double T_final = 0.01;

    // Checkpoint every 20 steps for faster partial re-sim
    const int CP_INTERVAL = 20;
    const int NUM_CP = (N + CP_INTERVAL - 1) / CP_INTERVAL;
    FastState checkpoints[10]; // checkpoints[i] = state at step i*CP_INTERVAL
    bool cp_valid[10];
    memset(cp_valid, 0, sizeof(cp_valid));

    auto rebuild_checkpoints = [&]() {
        FastState st;
        st.init(M, initial_stacks);
        for (int k = 0; k < N; k++) {
            if (k % CP_INTERVAL == 0 && k / CP_INTERVAL < NUM_CP) {
                checkpoints[k / CP_INTERVAL] = st;
                cp_valid[k / CP_INTERVAL] = true;
            }
            st.apply_step(k, current_plan[k], M);
        }
    };

    rebuild_checkpoints();

    PlanEntry new_plan[200];
    int iter_count = 0;
    int since_rebuild = 0;

    while (true) {
        if ((iter_count & 63) == 0) {
            double elapsed = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
            if (elapsed >= TIME_LIMIT_SECONDS) break;
        }
        iter_count++;

        double elapsed = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
        if (elapsed >= TIME_LIMIT_SECONDS) break;
        double progress = (elapsed - sa_start) / sa_budget;
        if (progress > 1.0) break;
        double T = T_init * std::pow(T_final / T_init, progress);

        memcpy(new_plan, current_plan, sizeof(PlanEntry) * N);

        int change_start = 0;
        double op = rng.randdbl();

        if (op < 0.40) {
            int k = rng.randint(0, N - 1);
            change_start = k;
            new_plan[k].dest_lower = rng.randint(0, M - 1);
        } else if (op < 0.65) {
            int start = rng.randint(0, N - 1);
            int len = rng.randint(2, std::min(N - start, 20));
            change_start = start;
            for (int i = 0; i < len; i++) {
                new_plan[start + i].dest_lower = rng.randint(0, M - 1);
            }
        } else if (op < 0.80) {
            int k = rng.randint(0, N - 1);
            change_start = k;
            if (new_plan[k].split_pos > 0) {
                if (rng.randdbl() < 0.4) {
                    new_plan[k].split_pos = 0;
                } else {
                    new_plan[k].split_pos = rng.randint(1, 12);
                    new_plan[k].dest_upper = rng.randint(0, M - 1);
                }
            } else {
                new_plan[k].split_pos = rng.randint(1, 10);
                new_plan[k].dest_upper = rng.randint(0, M - 1);
            }
        } else if (op < 0.90) {
            int k = rng.randint(0, N - 1);
            change_start = k;
            new_plan[k].dest_upper = rng.randint(0, M - 1);
        } else {
            int k1 = rng.randint(0, N - 1);
            int k2 = rng.randint(0, N - 1);
            change_start = std::min(k1, k2);
            std::swap(new_plan[k1].dest_lower, new_plan[k2].dest_lower);
        }

        // Find nearest checkpoint at or before change_start
        long long new_energy;
        int cp_idx = change_start / CP_INTERVAL;
        if (cp_idx > 0 && cp_valid[cp_idx]) {
            FastState st = checkpoints[cp_idx];
            int cp_step = cp_idx * CP_INTERVAL;
            // Simulate from checkpoint to change_start using new_plan (which is same as current_plan before change_start)
            for (int k = cp_step; k < change_start; k++) st.apply_step(k, new_plan[k], M);
            new_energy = simulate_from(st, new_plan, change_start, N, M);
        } else {
            new_energy = simulate_energy_full(initial_stacks, new_plan, N, M);
        }

        long long delta = new_energy - current_energy;
        if (delta < 0 || rng.randdbl() < std::exp(-(double)delta / T)) {
            current_energy = new_energy;
            memcpy(current_plan, new_plan, sizeof(PlanEntry) * N);
            if (new_energy < best_energy) {
                best_energy = new_energy;
                memcpy(best_plan, new_plan, sizeof(PlanEntry) * N);
            }
            // Invalidate checkpoints at or after change_start
            for (int i = cp_idx; i < NUM_CP; i++) cp_valid[i] = false;
            since_rebuild++;
            if (since_rebuild >= 500) {
                rebuild_checkpoints();
                since_rebuild = 0;
            }
        }
    }

    output_solution(initial_stacks, best_plan, N, M);
    return 0;
}
