    FastState st;
    st.init(M, initial);
    for (int k = 0; k < N; k++) st.apply_step(k, plan[k], M);
    return st.energy;
}

long long simulate_from(FastState& st, const PlanEntry* plan, int k_start, int N, int M) {
    for (int k = k_start; k < N; k++) st.apply_step(k, plan[k], M);
    return st.energy;
}

FastState get_state_at(const std::vector<std::vector<int>>& initial, const PlanEntry* plan,
                       int k_limit, int M) {
    FastState st;
    st.init(M, initial);
    for (int k = 0; k < k_limit; k++) st.apply_step(k, plan[k], M);
    return st;
}

double eval_dest(const FastState& st, int target_k, int src, int h, int num_above, int dest, int N) {
    double score = 0;
    int dsz = st.stack_sz[dest];
    int lookahead = 15;

    if (dsz == 0) {
