    // SA optimization with checkpointing
    double sa_start = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
    double sa_budget = TIME_LIMIT_SECONDS - sa_start;
    double T_init = 35.0;
    double T_final = 0.01;

    // Checkpoint every 20 steps for faster partial re-sim
    const int CP_INTERVAL = 20;
    const int NUM_CP = (N + CP_INTERVAL - 1) / CP_INTERVAL;
    FastState checkpoints[10]; // checkpoints[i] = state at step i*CP_INTERVAL
    bool cp_valid[10];
    memset(cp_valid, 0, sizeof(cp_valid));

    auto rebuild_checkpoints = [&]() {
        FastState st;
        st.init(M, initial_stacks);
        for (int k = 0; k < N; k++) {
            if (k % CP_INTERVAL == 0 && k / CP_INTERVAL < NUM_CP) {
