// split_pos>0 && < num_above: split top sp to dest_upper, rest to dest_lower

auto GLOBAL_START_TIME = std::chrono::steady_clock::now();
const double TIME_LIMIT_SECONDS = 1.92;

struct RNG {
    uint64_t s;
    RNG() : s(std::chrono::steady_clock::now().time_since_epoch().count() ^ 0xABCD1234ULL) {
        if (s == 0) s = 1;
    }
    inline uint64_t next() { s ^= s << 13; s ^= s >> 7; s ^= s << 17; return s; }
    inline int randint(int lo, int hi) { return lo + (int)(next() % (uint64_t)(hi - lo + 1)); }
    inline double randdbl() { return (next() & 0xFFFFFFFF) / 4294967296.0; }
} rng;

struct PlanEntry {
    int8_t split_pos;
    int8_t dest_lower;
    int8_t dest_upper;
};

struct FastState {
    int stacks[10][420];
    int stack_sz[10];
    int box_stack[200];
    int box_height[200];
    long long energy;
    int op_count;

    void init(int M, const std::vector<std::vector<int>>& initial) {
        energy = 0;
        op_count = 0;
        for (int i = 0; i < M; i++) {
            stack_sz[i] = (int)initial[i].size();
            for (int j = 0; j < stack_sz[i]; j++) {
                stacks[i][j] = initial[i][j];
                box_stack[initial[i][j]] = i;
                box_height[initial[i][j]] = j;
            }
        }
    }

    inline void move_block(int num_boxes, int dest, int src, int h) {
        int dh = stack_sz[dest];
        memcpy(&stacks[dest][dh], &stacks[src][h], num_boxes * sizeof(int));
        for (int i = 0; i < num_boxes; i++) {
            int b = stacks[dest][dh + i];
            box_stack[b] = dest;
            box_height[b] = dh + i;
        }
        stack_sz[dest] += num_boxes;
        stack_sz[src] = h;
        energy += (num_boxes + 1);
        op_count++;
    }

    inline void carry_out(int box_val) {
        stack_sz[box_stack[box_val]]--;
        op_count++;
    }

    inline void apply_step(int k, const PlanEntry& pe, int M) {
        int src = box_stack[k];
        int h = box_height[k];
        int num_above = stack_sz[src] - 1 - h;
        if (num_above > 0) {
