            for (int j = 0; j < stack_sz[i]; j++) {
                stacks[i][j] = initial[i][j];
                box_stack[initial[i][j]] = i;
                box_height[initial[i][j]] = j;
            }
        }
    }

    inline void move_block(int num_boxes, int dest, int src, int h) {
        int dh = stack_sz[dest];
        memcpy(&stacks[dest][dh], &stacks[src][h], num_boxes * sizeof(int));
        for (int i = 0; i < num_boxes; i++) {
            int b = stacks[dest][dh + i];
            box_stack[b] = dest;
            box_height[b] = dh + i;
        }
        stack_sz[dest] += num_boxes;
        stack_sz[src] = h;
        energy += (num_boxes + 1);
        op_count++;
