// Approach: Each target k has a plan entry (split_pos, dest_lower, dest_upper).
// split_pos=0: move all boxes above target to dest_lower
// split_pos>0 && < num_above: split top sp to dest_upper, rest to dest_lower
// Uses vector-based state + SA.

auto GLOBAL_START_TIME = std::chrono::steady_clock::now();
const double TIME_LIMIT_SECONDS = 1.92;

struct RNG {
    std::mt19937 rng;
    RNG() : rng(std::chrono::steady_clock::now().time_since_epoch().count()) {}
    int randint(int lo, int hi) {
        return std::uniform_int_distribution<int>(lo, hi)(rng);
    }
    double randdbl() {
        return std::uniform_real_distribution<double>(0.0, 1.0)(rng);
    }
} rng;

struct PlanEntry {
    int split_pos;   // 0 = no split
    int dest_lower;  // destination for lower portion (or all)
    int dest_upper;  // destination for upper portion (if split)
};

struct State {
    std::vector<std::vector<int>> stacks;
    int box_stack[200];
    int box_height[200];
    long long energy;

    void init(int M, const std::vector<std::vector<int>>& initial) {
        energy = 0;
        stacks = initial;
        for (int i = 0; i < M; i++) {
            for (int j = 0; j < (int)stacks[i].size(); j++) {
                box_stack[stacks[i][j]] = i;
                box_height[stacks[i][j]] = j;
            }
        }
    }

    void move_block(int src, int h, int num_boxes, int dest) {
        auto& sv = stacks[src];
        auto& dv = stacks[dest];
        int dh = (int)dv.size();
        dv.insert(dv.end(), sv.begin() + h, sv.begin() + h + num_boxes);
        for (int i = 0; i < num_boxes; i++) {
            int b = dv[dh + i];
            box_stack[b] = dest;
            box_height[b] = dh + i;
        }
        sv.erase(sv.begin() + h, sv.begin() + h + num_boxes);
        energy += (num_boxes + 1);
    }

    void carry_out(int box_val) {
        int src = box_stack[box_val];
        stacks[src].pop_back();
    }

    void apply_step(int k, const PlanEntry& pe, int M) {
        int src = box_stack[k];
        int h = box_height[k];
        int num_above = (int)stacks[src].size() - 1 - h;
        if (num_above > 0) {
            int sp = pe.split_pos;
            int dl = pe.dest_lower;
            int du = pe.dest_upper;
            if (dl == src) dl = (src + 1) % M;
            if (du == src) du = (src + 1) % M;
            if (sp >= num_above) sp = 0;
            if (sp > 0) {
                // Split: move top sp to du, rest to dl
                int top_h = h + 1 + (num_above - sp);
                move_block(src, top_h, sp, du);
                // After removing top sp, the remaining are at h+1..h+num_above-sp
                move_block(src, h + 1, num_above - sp, dl);
            } else {
                move_block(src, h + 1, num_above, dl);
            }
        }
        carry_out(k);
    }
};

long long simulate_energy(const std::vector<std::vector<int>>& initial, const std::vector<PlanEntry>& plan,
                          int N, int M) {
    State st;
    st.init(M, initial);
    for (int k = 0; k < N; k++) st.apply_step(k, plan[k], M);
    return st.energy;
}

double eval_dest(const State& st, int target_k, int src, int h, int num_above, int dest, int N) {
    double score = 0;
    int dsz = (int)st.stacks[dest].size();
    int lookahead = 15;

    if (dsz == 0) {
        score -= 400.0;
    } else {
        score += (double)dsz * 0.3;
        for (int j = 0; j < dsz; j++) {
            int b = st.stacks[dest][j];
            if (b > target_k && b < target_k + lookahead) {
                score += 6.0 * num_above;
            }
        }
    }

    for (int i = 0; i < num_above; i++) {
        int b = st.stacks[src][h + 1 + i];
        if (b > target_k && b < target_k + lookahead) {
            int boxes_on_top = num_above - 1 - i;
            score += 3.5 * boxes_on_top;
        }
    }

    return score;
}

std::vector<PlanEntry> generate_greedy_plan(const std::vector<std::vector<int>>& initial, int N, int M) {
    std::vector<PlanEntry> plan(N);
    State st;
    st.init(M, initial);

    for (int k = 0; k < N; k++) {
        int src = st.box_stack[k];
        int h = st.box_height[k];
