#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <limits>
#include <chrono>
#include <random>
#include <cmath>
#include <utility>

// N=200, M=10. Greedy + SA on destination choices.
// Key idea: For each target box k, when boxes above need moving,
// we can optionally SPLIT the block: move top portion to one dest,
// bottom portion to another. This allows separating soon-needed boxes.
// Energy cost for split: extra (upper_count+1) but saves future moves.

auto GLOBAL_START_TIME = std::chrono::steady_clock::now();
const double TIME_LIMIT_SECONDS = 1.85;

struct RNG {
    std::mt19937 rng;
    RNG() : rng(std::chrono::steady_clock::now().time_since_epoch().count()) {}
    int randint(int lo, int hi) {
        return std::uniform_int_distribution<int>(lo, hi)(rng);
    }
    double randdbl() {
        return std::uniform_real_distribution<double>(0.0, 1.0)(rng);
    }
} rng;

struct PlanEntry {
    int split_pos;   // 0 = no split, >0 = split top sp boxes off
    int dest_lower;  // destination for lower part (or all if no split)
    int dest_upper;  // destination for upper part (only if split)
};

struct State {
    std::vector<std::vector<int>> stacks;
    int box_stack[200];
    int box_height[200];
    long long energy;

    void init(int M, const std::vector<std::vector<int>>& initial) {
        energy = 0;
        stacks = initial;
        for (int i = 0; i < M; i++) {
            for (int j = 0; j < (int)stacks[i].size(); j++) {
                box_stack[stacks[i][j]] = i;
                box_height[stacks[i][j]] = j;
            }
        }
    }

    void move_block(int src, int h, int num_boxes, int dest) {
        auto& sv = stacks[src];
        auto& dv = stacks[dest];
        int dh = (int)dv.size();
        dv.insert(dv.end(), sv.begin() + h, sv.begin() + h + num_boxes);
        for (int i = 0; i < num_boxes; i++) {
            box_stack[dv[dh + i]] = dest;
            box_height[dv[dh + i]] = dh + i;
        }
        sv.erase(sv.begin() + h, sv.begin() + h + num_boxes);
        energy += (num_boxes + 1);
    }

    void carry_out(int box_val) {
        stacks[box_stack[box_val]].pop_back();
    }

    void apply_step(int k, const PlanEntry& pe, int M) {
        int src = box_stack[k];
        int h = box_height[k];
        int num_above = (int)stacks[src].size() - 1 - h;
        if (num_above > 0) {
            int sp = pe.split_pos;
            int dl = pe.dest_lower;
            int du = pe.dest_upper;
            if (dl == src) dl = (src + 1) % M;
            if (du == src) du = (src + 1) % M;
            if (sp <= 0 || sp >= num_above) {
                // No split
                move_block(src, h + 1, num_above, dl);
            } else {
                // Split: move top sp to du first
                int top_h = h + 1 + (num_above - sp);
                move_block(src, top_h, sp, du);
                // Remaining (num_above - sp) still at h+1
                move_block(src, h + 1, num_above - sp, dl);
            }
        }
        carry_out(k);
    }
};

long long simulate_energy(const std::vector<std::vector<int>>& initial, const std::vector<PlanEntry>& plan,
                          int N, int M) {
    State st;
    st.init(M, initial);
    for (int k = 0; k < N; k++) st.apply_step(k, plan[k], M);
    return st.energy;
}

double eval_dest(const State& st, int target_k, int src, int h, int num_above, int dest, int N) {
    double score = 0;
    const auto& dv = st.stacks[dest];
    int dsz = (int)dv.size();
    int lookahead = 15;

    if (dsz == 0) {
        score -= 400.0;
    } else {
        score += (double)dsz * 0.3;
        for (int j = 0; j < dsz; j++) {
            int b = dv[j];
            if (b > target_k && b < target_k + lookahead) {
                score += 6.0 * num_above;
            }
        }
    }

    for (int i = 0; i < num_above; i++) {
        int b = st.stacks[src][h + 1 + i];
        if (b > target_k && b < target_k + lookahead) {
            score += 3.5 * (num_above - 1 - i);
        }
    }

    return score;
}

std::vector<PlanEntry> generate_greedy_plan(const std::vector<std::vector<int>>& initial, int N, int M) {
    std::vector<PlanEntry> plan(N);
    State st;
    st.init(M, initial);

    for (int k = 0; k < N; k++) {
        int src = st.box_stack[k];
        int h = st.box_height[k];
        int num_above = (int)st.stacks[src].size() - 1 - h;

        if (num_above == 0) {
            plan[k] = {0, src, 0};
            st.carry_out(k);
            continue;
        }

        double best_score = 1e18;
        int best_dest = (src + 1) % M;
        for (int d = 0; d < M; d++) {
            if (d == src) continue;
            double sc = eval_dest(st, k, src, h, num_above, d, N);
            if (sc < best_score) {
                best_score = sc;
                best_dest = d;
            }
        }

        plan[k] = {0, best_dest, 0};
        st.move_block(src, h + 1, num_above, best_dest);
        st.carry_out(k);
    }
    return plan;
}

void output_solution(const std::vector<std::vector<int>>& initial, const std::vector<PlanEntry>& plan, int N, int M) {
    State st;
    st.init(M, initial);

    for (int k = 0; k < N; k++) {
        int src = st.box_stack[k];
        int h = st.box_height[k];
        int num_above = (int)st.stacks[src].size() - 1 - h;

        if (num_above > 0) {
            int sp = plan[k].split_pos;
            int dl = plan[k].dest_lower;
            int du = plan[k].dest_upper;
            if (dl == src) dl = (src + 1) % M;
            if (du == src) du = (src + 1) % M;
            if (sp <= 0 || sp >= num_above) sp = 0;

            if (sp > 0) {
                int top_h = h + 1 + (num_above - sp);
                int top_box = st.stacks[src][top_h];
                std::cout << (top_box + 1) << " " << (du + 1) << "\n";
                st.move_block(src, top_h, sp, du);

                int lower_box = st.stacks[src][h + 1];
                std::cout << (lower_box + 1) << " " << (dl + 1) << "\n";
                st.move_block(src, h + 1, num_above - sp, dl);
            } else {
                int first_box = st.stacks[src][h + 1];
                std::cout << (first_box + 1) << " " << (dl + 1) << "\n";
                st.move_block(src, h + 1, num_above, dl);
            }
        }
        std::cout << (k + 1) << " " << 0 << "\n";
        st.carry_out(k);
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;
    std::vector<std::vector<int>> initial_stacks(M, std::vector<int>(N / M));
    for (int i = 0; i < M; i++) {
        for (int j = 0; j < N / M; j++) {
            std::cin >> initial_stacks[i][j];
            initial_stacks[i][j]--;
        }
    }

    // Generate initial greedy plan
    std::vector<PlanEntry> best_plan = generate_greedy_plan(initial_stacks, N, M);
    long long best_energy = simulate_energy(initial_stacks, best_plan, N, M);

    std::vector<PlanEntry> current_plan = best_plan;
    long long current_energy = best_energy;

    // SA optimization
    double sa_start = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
    double sa_budget = TIME_LIMIT_SECONDS - sa_start;
    if (sa_budget < 0.01) sa_budget = 0.01;
    double T_init = 35.0;
    double T_final = 0.01;

    while (true) {
        double elapsed = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
        if (elapsed >= TIME_LIMIT_SECONDS) break;
        double progress = (elapsed - sa_start) / sa_budget;
        if (progress > 1.0) break;
        double T = T_init * std::pow(T_final / T_init, progress);

        std::vector<PlanEntry> new_plan = current_plan;
        double op = rng.randdbl();

        if (op < 0.40) {
            int k = rng.randint(0, N - 1);
            new_plan[k].dest_lower = rng.randint(0, M - 1);
        } else if (op < 0.60) {
            int start = rng.randint(0, N - 1);
            int len = rng.randint(2, std::min(N - start, 15));
            for (int i = 0; i < len; i++) {
                new_plan[start + i].dest_lower = rng.randint(0, M - 1);
            }
        } else if (op < 0.75) {
            int k = rng.randint(0, N - 1);
            if (new_plan[k].split_pos > 0) {
                if (rng.randdbl() < 0.4) {
                    new_plan[k].split_pos = 0;
                } else {
                    new_plan[k].split_pos = rng.randint(1, 12);
                    new_plan[k].dest_upper = rng.randint(0, M - 1);
                }
            } else {
                new_plan[k].split_pos = rng.randint(1, 10);
                new_plan[k].dest_upper = rng.randint(0, M - 1);
            }
        } else if (op < 0.87) {
            int k = rng.randint(0, N - 1);
            new_plan[k].dest_upper = rng.randint(0, M - 1);
        } else {
            int k1 = rng.randint(0, N - 1);
            int k2 = rng.randint(0, N - 1);
            std::swap(new_plan[k1].dest_lower, new_plan[k2].dest_lower);
        }

        long long new_energy = simulate_energy(initial_stacks, new_plan, N, M);

        long long delta = new_energy - current_energy;
        if (delta < 0 || rng.randdbl() < std::exp(-(double)delta / T)) {
            current_energy = new_energy;
            current_plan = std::move(new_plan);
            if (current_energy < best_energy) {
                best_energy = current_energy;
                best_plan = current_plan;
            }
        }
    }

    output_solution(initial_stacks, best_plan, N, M);
    return 0;
}
