// N=200, M=10. Greedy + SA with block-splitting optimization.
// Key idea: for each target box, optionally split the block above it
// into two portions routed to different stacks.

auto GLOBAL_START_TIME = std::chrono::steady_clock::now();
const double TIME_LIMIT_SECONDS = 1.80;

struct RNG {
    unsigned long long s;
    RNG() { s = std::chrono::steady_clock::now().time_since_epoch().count(); if (!s) s = 1; }
    unsigned long long next() { s ^= s << 13; s ^= s >> 7; s ^= s << 17; return s; }
    int randint(int lo, int hi) { return lo + (int)(next() % (unsigned long long)(hi - lo + 1)); }
    double randdbl() { return (double)(next() % 1000000000ULL) / 1000000000.0; }
} rng;

struct PlanEntry {
    int split_pos;
    int dest_lower;
    int dest_upper;
};

struct FastState {
    int stacks[10][420];
    int stack_sz[10];
    int box_stack[200];
    int box_height[200];
    long long energy;

    void init(int M, const std::vector<std::vector<int>>& initial) {
        energy = 0;
        for (int i = 0; i < M; i++) {
            stack_sz[i] = (int)initial[i].size();
            for (int j = 0; j < stack_sz[i]; j++) {
                stacks[i][j] = initial[i][j];
                box_stack[initial[i][j]] = i;
                box_height[initial[i][j]] = j;
            }
        }
    }

    void move_block(int src, int h, int num_boxes, int dest) {
        int dh = stack_sz[dest];
        for (int i = 0; i < num_boxes; i++) {
            int b = stacks[src][h + i];
            stacks[dest][dh + i] = b;
            box_stack[b] = dest;
            box_height[b] = dh + i;
        }
        stack_sz[dest] += num_boxes;
        stack_sz[src] = h;
        energy += (num_boxes + 1);
    }

    void carry_out(int box_val) {
        stack_sz[box_stack[box_val]]--;
    }

    void apply_step(int k, const PlanEntry& pe, int M) {
        int src = box_stack[k];
        int h = box_height[k];
        int num_above = stack_sz[src] - 1 - h;
        if (num_above > 0) {
            int sp = pe.split_pos;
            int dl = pe.dest_lower;
            int du = pe.dest_upper;
            if (dl == src) dl = (src + 1) % M;
            if (du == src) du = (src + 1) % M;
            if (sp > 0 && sp < num_above) {
                int top_h = h + 1 + (num_above - sp);
                move_block(src, top_h, sp, du);
                move_block(src, h + 1, num_above - sp, dl);
            } else {
                move_block(src, h + 1, num_above, dl);
            }
        }
        carry_out(k);
    }
};

double eval_dest(const FastState& st, int target_k, int src, int h, int num_above, int dest) {
    double score = 0;
    int dsz = st.stack_sz[dest];
    int lookahead = 15;

    if (dsz == 0) {
        score -= 400.0;
    } else {
        score += (double)dsz * 0.3;
        for (int j = 0; j < dsz; j++) {
            int b = st.stacks[dest][j];
            if (b > target_k && b < target_k + lookahead) {
                score += 6.0 * num_above;
            }
        }
    }

    for (int i = 0; i < num_above; i++) {
        int b = st.stacks[src][h + 1 + i];
        if (b > target_k && b < target_k + lookahead) {
            score += 3.5 * (num_above - 1 - i);
        }
    }
    return score;
}

long long simulate_energy(const std::vector<std::vector<int>>& initial, const PlanEntry* plan, int N, int M) {
    FastState st;
    st.init(M, initial);
    for (int k = 0; k < N; k++) st.apply_step(k, plan[k], M);
    return st.energy;
}

void generate_greedy_plan(const std::vector<std::vector<int>>& initial, int N, int M, PlanEntry* plan) {
    FastState st;
    st.init(M, initial);
    for (int k = 0; k < N; k++) {
        int src = st.box_stack[k];
        int h = st.box_height[k];
        int num_above = st.stack_sz[src] - 1 - h;
        if (num_above == 0) {
            plan[k] = {0, src, 0};
            st.carry_out(k);
            continue;
        }
        double best_score = 1e18;
        int best_dest = (src + 1) % M;
        for (int d = 0; d < M; d++) {
            if (d == src) continue;
            double sc = eval_dest(st, k, src, h, num_above, d);
            if (sc < best_score) { best_score = sc; best_dest = d; }
        }
        plan[k] = {0, best_dest, 0};
        st.move_block(src, h + 1, num_above, best_dest);
        st.carry_out(k);
    }
}

void output_solution(const std::vector<std::vector<int>>& initial, const PlanEntry* plan, int N, int M) {
    FastState st;
    st.init(M, initial);
    for (int k = 0; k < N; k++) {
        int src = st.box_stack[k];
        int h = st.box_height[k];
        int num_above = st.stack_sz[src] - 1 - h;
        if (num_above > 0) {
            int sp = plan[k].split_pos;
            int dl = plan[k].dest_lower;
            int du = plan[k].dest_upper;
            if (dl == src) dl = (src + 1) % M;
            if (du == src) du = (src + 1) % M;
            if (sp > 0 && sp < num_above) {
                int top_h = h + 1 + (num_above - sp);
                std::cout << (st.stacks[src][top_h] + 1) << " " << (du + 1) << "\n";
                st.move_block(src, top_h, sp, du);
                std::cout << (st.stacks[src][h + 1] + 1) << " " << (dl + 1) << "\n";
                st.move_block(src, h + 1, num_above - sp, dl);
            } else {
                std::cout << (st.stacks[src][h + 1] + 1) << " " << (dl + 1) << "\n";
                st.move_block(src, h + 1, num_above, dl);
            }
        }
        std::cout << (k + 1) << " " << 0 << "\n";
        st.carry_out(k);
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;
    std::vector<std::vector<int>> initial_stacks(M, std::vector<int>(N / M));
    for (int i = 0; i < M; i++)
        for (int j = 0; j < N / M; j++) {
            std::cin >> initial_stacks[i][j];
            initial_stacks[i][j]--;
        }

    PlanEntry best_plan[200];
    generate_greedy_plan(initial_stacks, N, M, best_plan);
    long long best_energy = simulate_energy(initial_stacks, best_plan, N, M);

    PlanEntry current_plan[200];
    memcpy(current_plan, best_plan, sizeof(PlanEntry) * N);
    long long current_energy = best_energy;

    // SA
    double sa_start = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
    double sa_budget = TIME_LIMIT_SECONDS - sa_start;
    if (sa_budget < 0.01) { output_solution(initial_stacks, best_plan, N, M); return 0; }
    double T_init = 35.0;
    double T_final = 0.01;

    PlanEntry new_plan[200];

    while (true) {
        double elapsed = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
        if (elapsed >= TIME_LIMIT_SECONDS) break;
        double progress = (elapsed - sa_start) / sa_budget;
        if (progress > 1.0) break;
        double T = T_init * std::pow(T_final / T_init, progress);

        memcpy(new_plan, current_plan, sizeof(PlanEntry) * N);
        double op = rng.randdbl();

        if (op < 0.45) {
            int k = rng.randint(0, N - 1);
            new_plan[k].dest_lower = rng.randint(0, M - 1);
        } else if (op < 0.70) {
            int start = rng.randint(0, N - 1);
            int len = rng.randint(2, std::min(N - start, 15));
            for (int i = 0; i < len; i++)
                new_plan[start + i].dest_lower = rng.randint(0, M - 1);
        } else if (op < 0.82) {
            int k = rng.randint(0, N - 1);
            if (new_plan[k].split_pos > 0) {
                new_plan[k].split_pos = (rng.randdbl() < 0.4) ? 0 : rng.randint(1, 12);
            } else {
                new_plan[k].split_pos = rng.randint(1, 10);
            }
            new_plan[k].dest_upper = rng.randint(0, M - 1);
        } else if (op < 0.90) {
            int k = rng.randint(0, N - 1);
            new_plan[k].dest_upper = rng.randint(0, M - 1);
        } else {
            int k1 = rng.randint(0, N - 1);
            int k2 = rng.randint(0, N - 1);
            std::swap(new_plan[k1].dest_lower, new_plan[k2].dest_lower);
        }

        long long new_energy = simulate_energy(initial_stacks, new_plan, N, M);
        long long delta = new_energy - current_energy;
        if (delta < 0 || rng.randdbl() < std::exp(-(double)delta / T)) {
            current_energy = new_energy;
            memcpy(current_plan, new_plan, sizeof(PlanEntry) * N);
            if (new_energy < best_energy) {
                best_energy = new_energy;
                memcpy(best_plan, new_plan, sizeof(PlanEntry) * N);
            }
        }
    }

    output_solution(initial_stacks, best_plan, N, M);
    return 0;
}
